        if not (0 <= age <= 150):
            raise ValueError(f"Age must be 0-150, got {age}")
        self.name = name
        self.email = email
        self.age = age
        self.password_hash = ""

    def to_dict(self):
        return {"name": self.name, "email": self.email, "age": self.age}

