import secrets
import time
from typing import Optional

_sessions: dict[str, dict] = {}
SESSION_EXPIRY_SECONDS = 30 * 60  # 30 minutes

def create_session(user_id: int) -> str:
    """Create a new session, return token."""
    token = secrets.token_urlsafe(32)
    _sessions[token] = {
        "user_id": user_id,
        "created_at": time.time(),
        "last_active": time.time(),
    }
    return token

def validate_session(token: str) -> Optional[int]:
    """Return user_id if session is valid and not expired, else None."""
    session = _sessions.get(token)
    if session is None:
        return None
    if time.time() - session["last_active"] > SESSION_EXPIRY_SECONDS:
        expire_session(token)
        return None
    session["last_active"] = time.time()
    return session["user_id"]

def expire_session(token: str) -> None:
    """Remove a session."""
    _sessions.pop(token, None)

def active_session_count() -> int:
    """Return number of active sessions."""
    return len(_sessions)
